#!/bin/bash
yum update -y
yum install -y python3.11 python3.11-pip
mkdir -p /opt/hearth-ui/templates
cd /opt/hearth-ui

# Create app.py
cat > app.py << 'APPEOF'
from flask import Flask, render_template, request, jsonify
import requests, json
app = Flask(__name__)
API_ENDPOINT = 'https://mwf1h5nbxe.execute-api.us-east-1.amazonaws.com/prod/search'
@app.route('/')
def index():
    return render_template('index.html')
@app.route('/search', methods=['POST'])
def search():
    data = request.json
    query = data.get('q', '').strip()
    size = int(data.get('size', 30))
    filters = {}
    if data.get('price_min'): filters['price_min'] = int(data['price_min'])
    if data.get('price_max'): filters['price_max'] = int(data['price_max'])
    if data.get('beds_min'): filters['beds_min'] = int(data['beds_min'])
    if data.get('baths_min'): filters['baths_min'] = int(data['baths_min'])
    payload = {'q': query, 'size': size}
    if filters: payload['filters'] = filters
    try:
        response = requests.post(API_ENDPOINT, json=payload, headers={'Content-Type': 'application/json'}, timeout=30)
        response.raise_for_status()
        return jsonify(response.json())
    except Exception as e:
        return jsonify({'error': str(e)}), 500
if __name__ == '__main__':
    app.run(host='0.0.0.0', port=80, debug=False)
APPEOF

# Decompress HTML
base64 -d << 'HTMLEOF' | gunzip > templates/index.html

HTMLEOF

# Install dependencies and start service
python3.11 -m pip install flask requests
cat > /etc/systemd/system/hearth-ui.service << 'SVC'
[Unit]
Description=Hearth UI Flask App
After=network.target
[Service]
Type=simple
User=root
WorkingDirectory=/opt/hearth-ui
ExecStart=/usr/bin/python3.11 app.py
Restart=always
RestartSec=10
[Install]
WantedBy=multi-user.target
SVC

systemctl daemon-reload
systemctl enable hearth-ui
systemctl start hearth-ui
sleep 5
systemctl status hearth-ui --no-pager
